use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::marker::PhantomData;pub struct BinaryDecoder;impl Crack for Decoder<BinaryDecoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let cleaned: String = text.chars().filter(|c| *c == '0' || *c == '1' || c.is_whitespace()).collect();        let binary_str: String = cleaned.chars().filter(|c| *c == '0' || *c == '1').collect();        if binary_str.len() % 8 != 0 || binary_str.is_empty() {            return result;        }        let mut bytes = Vec::with_capacity(binary_str.len() / 8);        for chunk in binary_str.as_bytes().chunks(8) {            if chunk.len() == 8 {                let byte_str = std::str::from_utf8(chunk).unwrap();                if let Ok(byte) = u8::from_str_radix(byte_str, 2) {                    bytes.push(byte);                } else {                    return result;                }            } else {                return result;            }        }        if let Ok(decoded_str) = String::from_utf8(bytes) {            if check_string_success(&decoded_str, text) {                let check_result = checker.check_text(&decoded_str);                if check_result.is_identified {                    result.success = true;                    result.unencrypted_text = Some(vec![decoded_str]);                    result.checker_name = check_result.checker_name;                }            }        }        result    }    fn get_name(&self) -> &'static str { "Binary" }    fn get_popularity(&self) -> f32 { 0.5 }    fn get_tags(&self) -> &'static [&'static str] { &["binary", "decoder", "base"] }    fn get_description(&self) -> &'static str { "Binary decoding converts 8-bit binary sequences to ASCII text." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Binary_code" }}impl Decoder<BinaryDecoder> {    pub fn new() -> Self {        Decoder {            name: "Binary",            description: "Binary decoding converts 8-bit binary sequences to ASCII text.",            link: "https://en.wikipedia.org/wiki/Binary_code",            tags: vec!["binary", "decoder", "base"],            popularity: 0.5,            phantom: PhantomData,        }    }}



